214	    );
215	    // Ensure empty state
216	    expect(
217	      screen.getByText('No assigned disaster recovery policy found')
218	    ).toBeInTheDocument();
219	    expect(
220	      screen.getByText(
221	        /You have not enrolled this application yet. To protect your application,/i
222	      )
223	    ).toBeInTheDocument();
224	    // Check primary action is enabled
225	    expect(screen.getByText('Enroll application')).toBeEnabled();
226	  });
227	
228	  test('manage policy view test', async () => {
229	    testCase = 2;
230	    render(
231	      <AppManagePoliciesModal
232	        resource={mockApplication1}
233	        close={onClose}
234	        isOpen={true}
235	      />
236	    );
237	
238	    // Modal headers
239	    expect(screen.getByText('Manage disaster recovery')).toBeInTheDocument();
240	
241	    // DR information
242	    expect(
243	      screen.getByText('Disaster recovery policy details')
244	    ).toBeInTheDocument();
245	    expect(
246	      screen.getByText('Name: mock-policy-1 (Validated)')
247	    ).toBeInTheDocument();
248	    expect(
249	      screen.getByText('Replication policy: async, 5 minutes')
250	    ).toBeInTheDocument();
251	    expect(screen.getByText('Cluster: east-1, west-1')).toBeInTheDocument();
252	    expect(screen.getByText('Placement: mock-placement-1')).toBeInTheDocument();
253	    expect(screen.getByText('Label selector:')).toBeInTheDocument();
254	    expect(screen.getByText('pvc=pvc1')).toBeInTheDocument();
255	    expect(
256	      screen.getByText(/Volume: Last synced on Jun 6, 2023, 5:50 PM UTC/i)
257	    ).toBeInTheDocument();
258	  });
259	
260	  test('Assign policy action test', async () => {
261	    const user = userEvent.setup();
262	    testCase = 3;
263	    render(
264	      <AppManagePoliciesModal
265	        resource={mockApplication1}
266	        close={onClose}
267	        isOpen={true}
268	      />
269	    );
270	    // Open assign policy wizard
271	    await user.click(screen.getByText('Enroll application'));
272	
273	    // Step 1 - select a policy
274	    // Buttons
275	    expect(screen.getByText('Next')).toBeEnabled();
276	    expect(screen.getByText('Back')).toBeDisabled();
277	    // Policy selector
278	    expect(screen.getByText('Select a policy')).toBeEnabled();
279	    await user.click(screen.getByText('Select a policy'));
280	
281	    const policies = screen.getAllByText('mock-policy-1');
282	    expect(policies.length).toBeGreaterThan(0); // ensures it's rendered
283	    await user.click(policies[0]);
284	    expect(policies[0]).toBeInTheDocument();
285	    await user.click(screen.getByText('Next'));
286	
287	    // Step 2 - select a placement and labels
288	    // Buttons
289	    expect(screen.getByText('Next')).toBeEnabled();
290	    expect(screen.getByText('Back')).toBeEnabled();
291	    // PVC selector
292	    screen.getByText(
293	      /Use PVC label selectors to effortlessly specify the application resources that need protection. You can also create a custom PVC label selector if one doesn’t exists. For more information/i
294	    );
295	
296	    expect(screen.getByText('Application resource')).toBeInTheDocument();
297	    expect(screen.getByText('PVC label selector')).toBeInTheDocument();
298	    expect(screen.getByText('Select a placement')).toBeInTheDocument();
299	
300	    await user.click(screen.getByText('Select a placement'));
301	    const placement2Option = await screen.findByText('mock-placement-2');
302	    await user.click(placement2Option);
303	
304	    // Wait for placement selection to be processed
305	    await waitFor(() => {
306	      expect(screen.getByText('mock-placement-2')).toBeInTheDocument();
307	    });
308	
309	    // Find all dropdown buttons and look for the PVC label selector
310	    const allButtons = screen.getAllByRole('button');
311	    const labelButtons = allButtons.filter(
312	      (btn) =>
313	        btn.getAttribute('aria-expanded') !== null &&
314	        !btn.textContent?.includes('Next') &&
315	        !btn.textContent?.includes('Back') &&
316	        !btn.textContent?.includes('Close') &&
317	        !btn.textContent?.includes('mock-placement')
318	    );
319	
320	    if (labelButtons.length > 0) {
321	      await user.click(labelButtons[labelButtons.length - 1]);
322	      const appLabel = await screen.findByText('app=mock-application-2');
323	      await user.click(appLabel);
324	    }
325	
326	    // Click Next to proceed to review step
327	    const nextButtons = screen.getAllByText('Next');
328	    await user.click(nextButtons[nextButtons.length - 1]);
329	
330	    // Step 3 - review and assign
331	    // Buttons
332	    expect(screen.getByText('Assign')).toBeEnabled();
333	    expect(screen.getByText('Back')).toBeEnabled();
334	    expect(screen.getByText('Cancel')).toBeEnabled();
335	
336	    // Headers
337	    screen.getByText(/Policy/i, { selector: 'span' });
338	    // Labels
339	    expect(screen.getByText('Policy name:')).toBeInTheDocument();
340	    expect(screen.getByText('Clusters:')).toBeInTheDocument();
341	    expect(screen.getByText('Replication type:')).toBeInTheDocument();
342	    expect(screen.getByText('Sync interval:')).toBeInTheDocument();
343	    expect(screen.getByText('Application resource:')).toBeInTheDocument();
344	    expect(screen.getByText('PVC label selector:')).toBeInTheDocument();
345	    // Values
346	    expect(screen.getByText('mock-policy-1')).toBeInTheDocument();
347	    expect(screen.getByText('east-1, west-1')).toBeInTheDocument();
348	    expect(screen.getByText('Asynchronous')).toBeInTheDocument();
349	    expect(screen.getByText('5 minutes')).toBeInTheDocument();
350	    expect(screen.getByText('mock-placement-2')).toBeInTheDocument();
351	    expect(screen.getByText('app=mock-application-2')).toBeInTheDocument();
352	  });
353	});

